solutionCode:
function describeAccount(account) {
  return {
    lamports: account.lamports,
    owner: account.owner.toBase58(),
    dataLength: account.data.length,
    executable: account.executable,
  };
}

testCode:
const { PublicKey } = require("@solana/web3.js");

const mockAccount = {
  lamports: 2_039_280,
  owner: new PublicKey("TokenzQdBNbLqP5VEhdkAS6EPFLC1PHnBqCXEpPxuEb"),
  data: Buffer.from([1, 2, 3, 4, 5]),
  executable: false,
};

const result = describeAccount(mockAccount);
assert(result.lamports === 2_039_280, "lamports should match");
assert(result.owner === "TokenzQdBNbLqP5VEhdkAS6EPFLC1PHnBqCXEpPxuEb", "owner should be base58 string");
assert(result.dataLength === 5, "dataLength should be 5");
assert(result.executable === false, "executable should be false");
